import{_ as t,c as i,a0 as a,o as l}from"./chunks/framework.B6JXc2q-.js";const _=JSON.parse('{"title":"认证运行时恢复路径规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_runtime_reload_recovery_path.md","filePath":"spec/auth_runtime_reload_recovery_path.md"}'),r={name:"spec/auth_runtime_reload_recovery_path.md"};function d(o,e,n,c,u,s){return l(),i("div",null,e[0]||(e[0]=[a('<h1 id="认证运行时恢复路径规范" tabindex="-1">认证运行时恢复路径规范 <a class="header-anchor" href="#认证运行时恢复路径规范" aria-label="Permalink to &quot;认证运行时恢复路径规范&quot;">​</a></h1><p>版本：v1.1<br> 状态：1.0.9 专项约束文档<br> 最后更新：2026-04-09<br> 适用范围：<code>xiaomusic/auth.py</code> 内 runtime reload / <code>_try_login()</code> / runtime rebind / verify 路径的行为边界</p><hr><h2 id="_1-文档目的" tabindex="-1">1. 文档目的 <a class="header-anchor" href="#_1-文档目的" aria-label="Permalink to &quot;1. 文档目的&quot;">​</a></h2><p>本文档描述当前 runtime 恢复主路径的阶段边界、失败分类与可观测性要求。</p><p>本文档解决：</p><ul><li>runtime reload / login / verify / runtime swap 的阶段定义</li><li>login-stage failure 与 verify-stage failure 的区分</li><li>候选 runtime 进入 verify 的前置条件</li><li>本轮已确认通过的是哪一层，不是哪一层</li></ul><p>本文档不解决：</p><ul><li>fallback path 的独立验收</li><li>singleflight 的实机闭环</li><li>auto runtime reload 全量验收</li><li>auth / playback 交叉边界</li><li>spec rebuild 全量结论</li></ul><hr><h2 id="_2-术语与范围" tabindex="-1">2. 术语与范围 <a class="header-anchor" href="#_2-术语与范围" aria-label="Permalink to &quot;2. 术语与范围&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>定义</th></tr></thead><tbody><tr><td>runtime reload</td><td>从磁盘与当前认证材料出发，重建 runtime 的完整恢复流程</td></tr><tr><td><code>_try_login()</code></td><td>当前 auth runtime 恢复核心路径之一</td></tr><tr><td>token load</td><td>读取 token_store / auth.json / 登录输入快照</td></tr><tr><td>fresh session login</td><td>使用 fresh <code>ClientSession</code> 的 <code>MiAccount.login(&quot;micoapi&quot;)</code></td></tr><tr><td>candidate runtime</td><td>本轮登录成功后构建但尚未应用的候选 runtime</td></tr><tr><td>candidate runtime readiness</td><td>候选 runtime 的 account / cookie ready 判定</td></tr><tr><td>verify</td><td>调用 <code>device_list</code> 等方式验证候选 runtime 是否可用</td></tr><tr><td>runtime swap</td><td>将候选 runtime 原子应用到当前运行态</td></tr><tr><td>login-stage failure</td><td>失败发生在 login 或进入 verify 前的准备阶段</td></tr><tr><td>verify-stage failure</td><td>登录成功且候选 runtime ready 后，失败发生在 verify 阶段</td></tr></tbody></table><p><strong>本文档中的 runtime reload 包含 <code>_try_login()</code> 主路径。</strong></p><p><strong>不包括</strong>：</p><ul><li>short session rebuild 的完整分支验收</li><li>primary / fallback 的全链验收</li><li>manual QR login 本身</li></ul><hr><h2 id="_3-当前已知链路事实" tabindex="-1">3. 当前已知链路事实 <a class="header-anchor" href="#_3-当前已知链路事实" aria-label="Permalink to &quot;3. 当前已知链路事实&quot;">​</a></h2><p>以下为当前仓库与本轮验收口径已确认的现实前提：</p><ol><li><p><code>_try_login()</code> 已暴露出明确的阶段化观测字段，包括：</p><ul><li><code>login_result</code></li><li><code>token_changed_after_login</code></li><li><code>candidate_runtime_account_ready</code></li><li><code>candidate_runtime_cookie_ready</code></li><li><code>verify_attempted</code></li><li><code>verify_error_text</code></li><li><code>runtime_swap_attempted</code></li><li><code>runtime_swap_applied</code></li></ul></li><li><p>当前实现已经可以区分：</p><ul><li>login-stage failure</li><li>verify-stage failure</li></ul></li><li><p>当前主路径修补点已经收口到：</p><ul><li><strong>恢复登录前复用旧 session 会导致 <code>login_result=false</code></strong></li><li>改为 <strong>fresh session login</strong> 后，live 观察已恢复 healthy</li></ul></li><li><p>本轮 &gt;24h 观察确认的是：</p><ul><li>fresh session 修补后的 <code>_try_login()</code> 主路径稳定</li></ul></li><li><p>以上结论只覆盖当前主路径，不覆盖 spec rebuild 全量</p></li></ol><hr><h2 id="_4-当前主路径阶段定义" tabindex="-1">4. 当前主路径阶段定义 <a class="header-anchor" href="#_4-当前主路径阶段定义" aria-label="Permalink to &quot;4. 当前主路径阶段定义&quot;">​</a></h2><h3 id="_4-1-阶段顺序" tabindex="-1">4.1 阶段顺序 <a class="header-anchor" href="#_4-1-阶段顺序" aria-label="Permalink to &quot;4.1 阶段顺序&quot;">​</a></h3><p>当前 runtime 恢复主路径按以下阶段定义：</p><table tabindex="0"><thead><tr><th>阶段</th><th>说明</th><th>关键字段</th></tr></thead><tbody><tr><td>token load</td><td>重新加载 token_store / auth.json，准备登录输入</td><td><code>token_store_reloaded</code>、磁盘 token 可见性</td></tr><tr><td>fresh session login</td><td>使用 fresh <code>ClientSession</code> 创建新 <code>MiAccount</code>，执行 <code>login(&quot;micoapi&quot;)</code></td><td><code>login_result</code>、<code>token_changed_after_login</code></td></tr><tr><td>candidate runtime readiness</td><td>检查候选 runtime 的 account / cookie 是否 ready</td><td><code>candidate_runtime_account_ready</code>、<code>candidate_runtime_cookie_ready</code></td></tr><tr><td>verify</td><td>对候选 runtime 执行可用性验证</td><td><code>verify_attempted</code>、<code>verify_error_text</code></td></tr><tr><td>runtime swap</td><td>仅在 verify 成功后进行原子替换</td><td><code>runtime_swap_attempted</code>、<code>runtime_swap_applied</code></td></tr></tbody></table><h3 id="_4-2-阶段流转约束" tabindex="-1">4.2 阶段流转约束 <a class="header-anchor" href="#_4-2-阶段流转约束" aria-label="Permalink to &quot;4.2 阶段流转约束&quot;">​</a></h3><ul><li>只有 <code>login_result=true</code>，才允许进入 candidate runtime readiness</li><li>只有 <code>candidate_runtime_account_ready=true</code> 且 <code>candidate_runtime_cookie_ready=true</code>，才允许进入 verify</li><li>只有 verify 成功，才允许 <code>runtime_swap_applied=true</code></li></ul><hr><h2 id="_5-明确的禁止条件" tabindex="-1">5. 明确的禁止条件 <a class="header-anchor" href="#_5-明确的禁止条件" aria-label="Permalink to &quot;5. 明确的禁止条件&quot;">​</a></h2><h3 id="_5-1-login-失败后不得继续-verify" tabindex="-1">5.1 login 失败后不得继续 verify <a class="header-anchor" href="#_5-1-login-失败后不得继续-verify" aria-label="Permalink to &quot;5.1 login 失败后不得继续 verify&quot;">​</a></h3><p>当：</p><ul><li><code>login_result=false</code></li></ul><p>则：</p><ul><li><code>verify_attempted</code> 必须为 <code>false</code></li><li><code>runtime_swap_attempted</code> 不应进入真正应用阶段</li><li><code>runtime_swap_applied</code> 必须为 <code>false</code></li></ul><h3 id="_5-2-candidate-runtime-未-ready-时不得继续-verify" tabindex="-1">5.2 candidate runtime 未 ready 时不得继续 verify <a class="header-anchor" href="#_5-2-candidate-runtime-未-ready-时不得继续-verify" aria-label="Permalink to &quot;5.2 candidate runtime 未 ready 时不得继续 verify&quot;">​</a></h3><p>当任一条件成立：</p><ul><li><code>candidate_runtime_account_ready=false</code></li><li><code>candidate_runtime_cookie_ready=false</code></li></ul><p>则：</p><ul><li>不得继续进入 verify</li><li>不得把这类失败伪装成 verify-stage failure</li></ul><h3 id="_5-3-verify-失败时不得污染旧-runtime" tabindex="-1">5.3 verify 失败时不得污染旧 runtime <a class="header-anchor" href="#_5-3-verify-失败时不得污染旧-runtime" aria-label="Permalink to &quot;5.3 verify 失败时不得污染旧 runtime&quot;">​</a></h3><p>当：</p><ul><li><code>verify_attempted=true</code></li><li>verify 失败</li></ul><p>则：</p><ul><li>候选 runtime 必须被丢弃</li><li><code>runtime_swap_applied=false</code></li><li>旧 runtime 必须保持不被污染</li></ul><hr><h2 id="_6-失败分类" tabindex="-1">6. 失败分类 <a class="header-anchor" href="#_6-失败分类" aria-label="Permalink to &quot;6. 失败分类&quot;">​</a></h2><h3 id="_6-1-login-stage-failure" tabindex="-1">6.1 login-stage failure <a class="header-anchor" href="#_6-1-login-stage-failure" aria-label="Permalink to &quot;6.1 login-stage failure&quot;">​</a></h3><p>典型特征：</p><ul><li><code>login_result=false</code>，或</li><li>login 虽成功，但 <code>candidate_runtime_account_ready=false</code> / <code>candidate_runtime_cookie_ready=false</code></li></ul><p>应归类为：</p><ul><li>登录阶段失败</li><li>候选 runtime 准备阶段失败</li></ul><p>不应归类为：</p><ul><li>verify-stage failure</li></ul><h3 id="_6-2-verify-stage-failure" tabindex="-1">6.2 verify-stage failure <a class="header-anchor" href="#_6-2-verify-stage-failure" aria-label="Permalink to &quot;6.2 verify-stage failure&quot;">​</a></h3><p>典型特征：</p><ul><li><code>login_result=true</code></li><li><code>candidate_runtime_account_ready=true</code></li><li><code>candidate_runtime_cookie_ready=true</code></li><li><code>verify_attempted=true</code></li><li><code>runtime_swap_applied=false</code></li></ul><p>语义：</p><ul><li>登录成功，候选 runtime 具备进入 verify 的条件</li><li>失败发生在 verify 阶段</li></ul><h3 id="_6-3-当前修补点的现实归因" tabindex="-1">6.3 当前修补点的现实归因 <a class="header-anchor" href="#_6-3-当前修补点的现实归因" aria-label="Permalink to &quot;6.3 当前修补点的现实归因&quot;">​</a></h3><p>当前主修补点不是“所有 verify 失败都已解决”，而是：</p><ul><li>旧行为中恢复登录复用旧 session，可能直接导致 <code>login_result=false</code></li><li>现在改为 fresh session login 后，主路径已恢复健康</li></ul><p>因此，本轮通过的是：</p><ul><li>fresh session 修补后的 <code>_try_login()</code> 主路径稳定</li></ul><p>不是：</p><ul><li>runtime reload 所有失败都已消失</li><li>verify 全量问题已清零</li></ul><hr><h2 id="_7-可观测性要求" tabindex="-1">7. 可观测性要求 <a class="header-anchor" href="#_7-可观测性要求" aria-label="Permalink to &quot;7. 可观测性要求&quot;">​</a></h2><h3 id="_7-1-必须稳定暴露的字段" tabindex="-1">7.1 必须稳定暴露的字段 <a class="header-anchor" href="#_7-1-必须稳定暴露的字段" aria-label="Permalink to &quot;7.1 必须稳定暴露的字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>login_result</code></td><td>登录是否成功</td></tr><tr><td><code>token_changed_after_login</code></td><td>登录后 token 是否变化</td></tr><tr><td><code>candidate_runtime_account_ready</code></td><td>候选 runtime 的 account 是否 ready</td></tr><tr><td><code>candidate_runtime_cookie_ready</code></td><td>候选 runtime 的 cookie 是否 ready</td></tr><tr><td><code>verify_attempted</code></td><td>是否进入 verify</td></tr><tr><td><code>verify_error_text</code></td><td>verify 错误文本</td></tr><tr><td><code>runtime_swap_attempted</code></td><td>是否尝试 runtime swap</td></tr><tr><td><code>runtime_swap_applied</code></td><td>是否应用 runtime swap</td></tr><tr><td><code>recovery_failure_count</code></td><td>恢复失败计数</td></tr></tbody></table><h3 id="_7-2-关键约束" tabindex="-1">7.2 关键约束 <a class="header-anchor" href="#_7-2-关键约束" aria-label="Permalink to &quot;7.2 关键约束&quot;">​</a></h3><ul><li>必须能区分 login-stage failure 与 verify-stage failure</li><li>必须能判断 verify 是否真正发生</li><li>必须能判断 verify 失败后是否污染旧 runtime</li><li>不允许把 fresh session 主路径通过写成 general rebuild 全量通过</li></ul><hr><h2 id="_8-与-auto-runtime-reload-的边界" tabindex="-1">8. 与 auto runtime reload 的边界 <a class="header-anchor" href="#_8-与-auto-runtime-reload-的边界" aria-label="Permalink to &quot;8. 与 auto runtime reload 的边界&quot;">​</a></h2><ul><li>auto runtime reload 只是触发方式</li><li>不改变 <code>_try_login()</code> 主路径的阶段语义</li><li>当前本轮已确认的是 <code>_try_login()</code> 主路径稳定</li><li><strong>不是 auto runtime reload 全量边界已完成验收</strong></li></ul><p>未覆盖范围仍包括：</p><ul><li>auto trigger 全边界</li><li>singleflight 实机闭环</li><li>fallback 独立验收</li><li>auth / playback 交叉边界</li><li>极端网络扰动</li></ul><hr><h2 id="_9-当前验收结论边界" tabindex="-1">9. 当前验收结论边界 <a class="header-anchor" href="#_9-当前验收结论边界" aria-label="Permalink to &quot;9. 当前验收结论边界&quot;">​</a></h2><h3 id="_9-1-已确认通过" tabindex="-1">9.1 已确认通过 <a class="header-anchor" href="#_9-1-已确认通过" aria-label="Permalink to &quot;9.1 已确认通过&quot;">​</a></h3><ul><li>fresh session 修补后的 <code>_try_login()</code> 主路径在 &gt;24h 窗口内稳定</li></ul><h3 id="_9-2-适用范围" tabindex="-1">9.2 适用范围 <a class="header-anchor" href="#_9-2-适用范围" aria-label="Permalink to &quot;9.2 适用范围&quot;">​</a></h3><ul><li>当前主路径</li><li>当前阶段化观测字段</li><li>login-stage / verify-stage 已可区分这一层</li></ul><h3 id="_9-3-不可外推范围" tabindex="-1">9.3 不可外推范围 <a class="header-anchor" href="#_9-3-不可外推范围" aria-label="Permalink to &quot;9.3 不可外推范围&quot;">​</a></h3><ul><li>spec rebuild 全量通过</li><li>auto runtime reload 全量通过</li><li>singleflight / fallback / cross-boundary 全量通过</li></ul><hr><h2 id="_10-非目标" tabindex="-1">10. 非目标 <a class="header-anchor" href="#_10-非目标" aria-label="Permalink to &quot;10. 非目标&quot;">​</a></h2><p>本文档不解决：</p><ul><li>Xiaomi 云端为什么返回 401</li><li>fallback path 的成功率问题</li><li>manual QR login 交互</li><li>整个 auth.py 模块拆分</li><li>大规模重构方案</li></ul>',87)]))}const f=t(r,[["render",d]]);export{_ as __pageData,f as default};
